class Solution:
    def friendRequests(self, n: int, restrictions: List[List[int]], requests: List[List[int]]) -> List[bool]:
        result = []
        parent = list(range(n))
        rank = [1] * n

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            rootx, rooty = find(x), find(y)
            if rootx != rooty:
                if rank[rootx] > rank[rooty]:
                    parent[rooty] = rootx
                elif rank[rootx] < rank[rooty]:
                    parent[rootx] = rooty
                else:
                    parent[rooty] = rootx
                    rank[rootx] += 1

        for u, v in requests:
            flag = True
            for x, y in restrictions:
                if find(u) == find(x) and find(v) == find(y):
                    flag = False
                    break
                if find(u) == find(y) and find(v) == find(x):
                    flag = False
                    break
            if flag:
                union(u, v)
            result.append(flag)
        return result
